using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool, Description("Gets the current weather for a given city.")]
    public static string GetWeather(
        [Description("The city name, e.g. 'Seattle'")] string city)
    {
        // Stub — replace with a real API call.
        return $"The weather in {city} is 72°F and sunny.";
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        Uri = "config://app/settings",
        Name = "App Settings",
        Description = "Returns the current application configuration.",
        MimeType = "application/json")]
    public static string GetAppSettings()
    {
        var config = new
        {
            version = "1.0.0",
            environment = "production",
            features = new { darkMode = true, notifications = true }
        };
        return System.Text.Json.JsonSerializer.Serialize(config);
    }
}

